import{_ as i,c as e,a,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),e("div",null,s[0]||(s[0]=[a(`<p>uni-app是国人开发的基于vue语法,可以编译成各个小程序的项目,不过由于种类多,且小程序api经常更改,uniapp会有较多bug</p><h1 id="vscode创建uniapp项目" tabindex="-1"><a class="header-anchor" href="#vscode创建uniapp项目"><span>vscode创建uniapp项目</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npx degit dcloudio/uni-preset-vue#vite demo</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>创建基于ts的项目</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npx degit dcloudio/uni-preset-vue#vite-ts demo</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>访问仓库失败处理</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npx @dcloudio/uvm</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>vue3创建的项目默认不安装api语法提示依赖,手动安装</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm i @dcloudio/types miniprogram-api-typings mini-types -D</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>安装uni-ui组件库 也有其他组件库可使用,但uni-ui组件库是跨平台的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm i @dcloudio/uni-ui</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>运行项目相关的命令在package.son文件中</p><p><strong>配置uni-ui类型(ts)</strong> uni-ui是js开发的,因此所有的uni-ui组件都没有类型,要想使用ts的类型检查需要导入第三方的软件包</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm i -D @uni-helper/uni-ui-types</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="自动导入规则的配置" tabindex="-1"><a class="header-anchor" href="#自动导入规则的配置"><span>自动导入规则的配置</span></a></h1><p>在pages.json文件中添加</p><div class="language-pages.json line-numbers-mode" data-highlighter="shiki" data-ext="pages.json" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  &quot;easycom&quot;: {</span></span>
<span class="line"><span>    &quot;autoscan&quot;: true,</span></span>
<span class="line"><span>    &quot;custom&quot;: {</span></span>
<span class="line"><span>	  // 以uni-开头的文件自动导入@dcloudio/uni-ui/lib/后续文件夹中的对应文件,$1是占位符表示uni-后面名字</span></span>
<span class="line"><span>      &quot;^uni-(.*)&quot;: &quot;@dcloudio/uni-ui/lib/uni-$1/uni-$1.vue&quot;,</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="ts配置" tabindex="-1"><a class="header-anchor" href="#ts配置"><span>ts配置</span></a></h3><p>安装ts类型校验</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm i-D @types/wechat-miniprogram @uni-helper/uni-app-types</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>ts配置文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&quot;compileroptions&quot;:{</span></span>
<span class="line"><span>	&quot;types&quot;:[</span></span>
<span class="line"><span>		&quot;@dcloudio/types&quot;,</span></span>
<span class="line"><span>		&quot;@types/wechat-miniprogram&quot;&quot;</span></span>
<span class="line"><span>		&quot;@uni-helper/uni-app-types&quot;</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>&quot;vueCompileroptions&quot;:{</span></span>
<span class="line"><span>	&quot;experimentalRuntimeMode&quot;:&quot;runtime-uniapp&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="持久化" tabindex="-1"><a class="header-anchor" href="#持久化"><span>持久化</span></a></h1><p>在uniapp中可以使用pinia持久化,但默认开启的持久化方式只适用于浏览器 需要对创建的store对象进行额外的配置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>persist: {</span></span>
<span class="line"><span>      storage: {</span></span>
<span class="line"><span>        getItem(key) {</span></span>
<span class="line"><span>          return uni.getStorageSync(key)</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        setItem(key, value) {</span></span>
<span class="line"><span>          uni.setStorageSync(key, value)</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="网络请求" tabindex="-1"><a class="header-anchor" href="#网络请求"><span>网络请求</span></a></h1><p>uni.request的success回调函数只是表示服务器响应成功，没处理响应状态码，业务中使用不方便 axios函数是只有响应状态码是2xx才调用resolve函数，表示获取数据成功，业务中使用更准确</p><h1 id="api" tabindex="-1"><a class="header-anchor" href="#api"><span>api</span></a></h1><h3 id="安全区域" tabindex="-1"><a class="header-anchor" href="#安全区域"><span>安全区域</span></a></h3><p>不同手机上的安全区域是不同的,所有内容都应放在安全区域内,否则就会被遮挡 对于非全面屏,小程序已经默认将状态栏区域排除在外 对于非全面屏,如:刘海,胶囊,挖孔,水滴等安全区域是不同的,如果不进行配置内容部分可能会被遮挡</p><p><code>uni.getSystemInfoSync()</code>函数用于获取系统信息,其中的safeAreaInsets是安全区域</p>`,31)]))}const r=i(l,[["render",d]]),c=JSON.parse('{"path":"/front/vue/8/","title":"8 uniapp","lang":"zh-CN","frontmatter":{"title":"8 uniapp","createTime":"2025/06/18 21:10:54","permalink":"/front/vue/8/"},"readingTime":{"minutes":1.96,"words":588},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/8 uniapp.md","headers":[]}');export{r as comp,c as data};
